module.exports = function(RED) {

    function createAgentNode(name, defaultPrompt) {
        return function(config) {
            RED.nodes.createNode(this, config);
            const node = this;
            node.name = config.name;
            node.seedingPrompt = config.seedingPrompt || defaultPrompt;
            node.model = config.model;

            node.on("input", function(msg) {
                // shared logic for all agents
                msg.payload = {
                    model: node.model,
                    prompt: node.seedingPrompt,
                    input: msg.payload
                };
                node.send(msg);
            });
        }
    }
    RED.nodes.registerType("Software Architect",
        createAgentNode("Software Architect", "Given an input text, adjust it to the needs of a Software Architect."));

    RED.nodes.registerType("Product Owner",
        createAgentNode("Product Owner", "Given an input text, adjust it to the needs of a Product Manager."));

    RED.nodes.registerType("Requirements Engineer",
        createAgentNode("Requirements Engineer", "Given an input text, adjust it to the needs of a Requirements Engineer."));

    RED.nodes.registerType("Software Developer",
        createAgentNode("Software Developer", "Given an input text, adjust it to the needs of a Software Developer."));

    RED.nodes.registerType("Software Tester",
        createAgentNode("Software Tester", "Given an input text, adjust it to the needs of a Software Tester."));
    
    RED.nodes.registerType("Custom Agent",
        createAgentNode("Custom Agent", ""));

}